import time
from functools import wraps
from typing import Callable, TypeVar, Tuple, Type, Any, cast

T = TypeVar("T")

def retry(
    max_attempts: int = 3,
    backoff_factor: float = 2.0,
    exceptions: Tuple[Type[BaseException], ...] = (Exception,),
) -> Callable[[Callable[..., T]], Callable[..., T]]:
    """
    Decorator that retries a function if specified exceptions occur.

    Args:
        max_attempts: Maximum number of attempts before raising the exception.
        backoff_factor: Multiplier for exponential backoff delay (seconds).
        exceptions: Exception types that trigger a retry.

    Returns:
        A decorated function that retries execution on failure.

    Example:
        @retry(max_attempts=3, backoff_factor=2)
        def fetch_data() -> str:
            ...
    """
    def decorator(func: Callable[..., T]) -> Callable[..., T]:
        @wraps(func)
        def wrapper(*args: Any, **kwargs: Any) -> T:
            delay = 1.0
            attempt = 0

            while True:
                try:
                    return func(*args, **kwargs)
                except exceptions:
                    attempt += 1
                    if attempt >= max_attempts:
                        raise
                    time.sleep(delay)
                    delay *= backoff_factor

        return cast(Callable[..., T], wrapper)

    return decorator
