import csv
import json

def _normalize_row(row):
    name = row['name'].strip().title()
    email = row['email'].strip().lower()
    age = int(row['age'])
    if age >= 18 and '@' in email:
        return {'name': name, 'email': email, 'age': age}
    return None

def process_csv(path):
    results = []
    with open(path) as f:
        reader = csv.DictReader(f)
        for row in reader:
            item = _normalize_row(row)
            if item:
                results.append(item)
    return results

def process_json(path):
    results = []
    with open(path) as f:
        data = json.load(f)
        for row in data:
            item = _normalize_row(row)
            if item:
                results.append(item)
    return results
